+                                    state.glob_index += 1;
+                                }
+
+                                state.skipToSeparator(path, is_end_invalid);
+                                in_globstar = true;
+                            }
+                        } else {
+                            state.glob_index += 1;
+                        }
+
+                        if (!in_globstar and state.path_index < path.len and isSeparator(path[state.path_index])) {
+                            state.wildcard = state.globstar;
+                        }
